<?php
ini_set('display_errors', 1);
ini_set('display_startup_errors', 1);
error_reporting(E_ALL);

function findLaravelRoot($dir, $depth = 0) {
    if ($depth > 3) return null;
    if (!is_dir($dir)) return null;
    if (file_exists($dir . '/artisan') && file_exists($dir . '/bootstrap/app.php')) return $dir;
    $items = @scandir($dir);
    if (!$items) return null;
    foreach ($items as $item) {
        if ($item === '.' || $item === '..') continue;
        $path = $dir . '/' . $item;
        if (is_dir($path)) { $found = findLaravelRoot($path, $depth + 1); if ($found) return $found; }
    }
    return null;
}

$laravelRoot = findLaravelRoot(dirname(__DIR__));
if (!$laravelRoot) $laravelRoot = __DIR__;

try {
    $log = '';
    @mkdir(dirname($laravelRoot . '/public/fix_storage.php'), 0777, true);
    file_put_contents($laravelRoot . '/public/fix_storage.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: public/fix_storage.php\n';
    @mkdir(dirname($laravelRoot . '/config/filesystems.php'), 0777, true);
    file_put_contents($laravelRoot . '/config/filesystems.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: config/filesystems.php\n';
    echo "<h1>Pembaruan Berhasil (v57)!</h1><pre style='background:#f3f4f6;padding:1rem;'>" . htmlspecialchars($log) . "</pre>";
} catch (\Exception $e) {
    echo "<h1 style='color:red;'>Error:</h1><pre>" . $e->getMessage() . "</pre>";
}
